// ─── FIREBASE SERVICE ───────────────────────────────────────────────────

import {
  collection,
  getDocs,
  addDoc,
  updateDoc,
  deleteDoc,
  doc,
  serverTimestamp
} from "firebase/firestore";

import {
  onAuthStateChanged
} from "firebase/auth";

import { db, auth } from "./firebaseConfig";

// ═══ RESOURCES ═══════════════════════════════════════════════════════════════

export async function getResources() {
  const snapshot = await getDocs(collection(db, "resources"));
  return snapshot.docs.map(doc => ({
    id: doc.id,
    ...doc.data()
  }));
}

export async function createResource(data) {
  const docRef = await addDoc(collection(db, "resources"), {
    ...data,
    createdAt: serverTimestamp()
  });
  return docRef.id;
}

export async function updateResource(id, data) {
  await updateDoc(doc(db, "resources", id), data);
}

export async function deleteResource(id) {
  await deleteDoc(doc(db, "resources", id));
}

// ═══ RESERVATIONS ════════════════════════════════════════════════════════════

export async function getReservations() {
  const snapshot = await getDocs(collection(db, "reservations"));
  return snapshot.docs.map(doc => ({
    id: doc.id,
    ...doc.data()
  }));
}

export async function createReservation(data) {
  const docRef = await addDoc(collection(db, "reservations"), {
    ...data,
    createdAt: serverTimestamp()
  });
  return docRef.id;
}

export async function updateReservation(id, data) {
  await updateDoc(doc(db, "reservations", id), data);
}

export async function deleteReservation(id) {
  await deleteDoc(doc(db, "reservations", id));
}

// ═══ LOANS ═══════════════════════════════════════════════════════════════════

export async function getLoans() {
  const snapshot = await getDocs(collection(db, "loans"));
  return snapshot.docs.map(doc => ({
    id: doc.id,
    ...doc.data()
  }));
}

export async function createLoan(data) {
  const docRef = await addDoc(collection(db, "loans"), {
    ...data,
    createdAt: serverTimestamp()
  });
  return docRef.id;
}

export async function updateLoan(id, data) {
  await updateDoc(doc(db, "loans", id), data);
}

export async function deleteLoan(id) {
  await deleteDoc(doc(db, "loans", id));
}

// ═══ USERS ═══════════════════════════════════════════════════════════════════

export async function getUsers() {
  const snapshot = await getDocs(collection(db, "users"));
  return snapshot.docs.map(doc => ({
    id: doc.id,
    ...doc.data()
  }));
}

export async function createUser(data) {
  const docRef = await addDoc(collection(db, "users"), {
    ...data,
    createdAt: serverTimestamp()
  });
  return docRef.id;
}

export async function updateUser(id, data) {
  await updateDoc(doc(db, "users", id), data);
}

// ═══ AUTH ═══════════════════════════════════════════════════════════════════

export async function getCurrentUser() {
  return new Promise((resolve) => {
    onAuthStateChanged(auth, (user) => {
      if (user) {
        resolve({
          id: user.uid,
          email: user.email
        });
      } else {
        resolve(null);
      }
    });
  });
}

// ═══ STATS ═══════════════════════════════════════════════════════════════════

export async function getStats() {
  const resources = await getResources();
  const loans = await getLoans();

  const totalResources = resources.length;

  const available = resources.filter(r => r.status === "available").length;
  const loaned = resources.filter(r => r.status === "loaned").length;
  const reserved = resources.filter(r => r.status === "reserved").length;
  const maintenance = resources.filter(r => r.status === "maintenance").length;

  return {
    totalResources,
    available,
    loaned,
    reserved,
    maintenance,
    totalLoansMonth: loans.length,
    punctualityRate: 100,
    delaysMonth: 0,
    incidentsMonth: 0,
  };
}
